    fputc(0x08, f); fputc(0x00, f);
    fputc(0x08, f); fputc(0x00, f);
    fputc(0x08, f); fputc(0x00, f);
    fputc(0x08, f); fputc(0x00, f);
    fputc(0x08, f); fputc(0x00, f);

    /* ExtraSamples array: 2 (ASSOCALPHA) */
    fputc(0x02, f); fputc(0x00, f);

    /* Pixel data: 64x64 CMYKA pixels (each pixel = 0x00,0x00,0x00,0x00,0x80) */
    {
        int i;
        for (i = 0; i < 4096; i++) {
            fputc(0x00, f);
            fputc(0x00, f);
            fputc(0x00, f);
            fputc(0x00, f);
            fputc(0x80, f);
        }
    }

    fclose(f);
    return 0;
}
